 {"id":"jeffreysprompts.com-h5qa","title":"E2E Tests: Comments and Discussions","description":"## Origin
Moved from jeffreysprompts_premium jeffreysprompts_premium-iu7h.

## Task
Create E2E tests for comment and discussion functionality.

## Why This Matters
- Community feature
- Complex interactions
- Moderation needed
- Notifications involved

## Test Scenarios

### 1. Adding Comments
```typescript
test('should add comment to prompt', async ({ page }) => {
  const prompt = await createPublicPrompt();

  await loginAsUser(page);
  await page.goto(`/prompts/${prompt.id}`);

  // Add comment
  await page.getByPlaceholder('Add a comment').fill('Great prompt!');
  await page.getByRole('button', { name: 'Post' }).click();

  // Should appear in list
  await expect(page.getByText('Great prompt!')).toBeVisible();
  await expect(page.getByTestId('comment-author')).toContainText(testUser.name);
});

test('should reply to comment', async ({ page }) => {
  const prompt = await createPublicPrompt();
  const comment = await createComment(prompt.id, 'Original comment');

  await loginAsUser(page);
  await page.goto(`/prompts/${prompt.id}`);

  // Click reply
  await page.getByRole('button', { name: 'Reply' }).click();
  await page.getByPlaceholder('Write a reply').fill('Thanks for the feedback!');
  await page.getByRole('button', { name: 'Post Reply' }).click();

  // Should show threaded reply
  await expect(page.getByText('Thanks for the feedback!')).toBeVisible();
  await expect(page.getByTestId('reply-indent')).toBeVisible();
});
```

### 2. Comment Actions
```typescript
test('should edit own comment', async ({ page }) => {
  const prompt = await createPublicPrompt();
  await loginAsUser(page);
  const comment = await createComment(prompt.id, 'Original text', testUser.id);

  await page.goto(`/prompts/${prompt.id}`);

  // Edit comment
  await page.getByRole('button', { name: 'Edit' }).click();
  await page.getByRole('textbox').fill('Updated text');
  await page.getByRole('button', { name: 'Save' }).click();

  // Should show updated text
  await expect(page.getByText('Updated text')).toBeVisible();
  await expect(page.getByText('(edited)')).toBeVisible();
});

test('should delete own comment', async ({ page }) => {
  const prompt = await createPublicPrompt();
  await loginAsUser(page);
  const comment = await createComment(prompt.id, 'To be deleted', testUser.id);

  await page.goto(`/prompts/${prompt.id}`);

  await page.getByRole('button', { name: 'Delete' }).click();
  await page.getByRole('button', { name: 'Confirm' }).click();

  // Should be removed
  await expect(page.getByText('To be deleted')).not.toBeVisible();
});

test('should upvote comment', async ({ page }) => {
  const prompt = await createPublicPrompt();
  const comment = await createComment(prompt.id, 'Helpful comment');

  await loginAsUser(page);
  await page.goto(`/prompts/${prompt.id}`);

  // Upvote
  await page.getByRole('button', { name: 'Upvote' }).click();

  // Count should increase
  await expect(page.getByTestId('upvote-count')).toContainText('1');
});
```

### 3. Comment Moderation
```typescript
test('should allow creator to hide comment', async ({ page }) => {
  const prompt = await createPublicPrompt(testUser.id);
  const comment = await createComment(prompt.id, 'Spam content', otherUser.id);

  await loginAs(page, testUser);
  await page.goto(`/prompts/${prompt.id}`);

  // Hide comment
  await page.getByRole('button', { name: 'Hide' }).click();

  // Comment should be hidden
  await expect(page.getByText('Spam content')).not.toBeVisible();
  await expect(page.getByText(/comment hidden/i)).toBeVisible();
});

test('should report inappropriate comment', async ({ page }) => {
  const prompt = await createPublicPrompt();
  const comment = await createComment(prompt.id, 'Inappropriate content');

  await loginAsUser(page);
  await page.goto(`/prompts/${prompt.id}`);

  // Report
  await page.getByRole('button', { name: 'Report' }).click();
  await page.getByLabel('Reason').selectOption('spam');
  await page.getByRole('button', { name: 'Submit Report' }).click();

  await expect(page.getByText(/reported/i)).toBeVisible();
});
```

### 4. Comments Notifications
```typescript
test('should notify creator of new comment', async ({ page }) => {
  const prompt = await createPublicPrompt(creatorUser.id);

  // Other user adds comment
  await loginAs(page, otherUser);
  await page.goto(`/prompts/${prompt.id}`);
  await page.getByPlaceholder('Add a comment').fill('New comment here');
  await page.getByRole('button', { name: 'Post' }).click();

  // Check creator notifications
  await loginAs(page, creatorUser);
  await page.goto('/notifications');

  await expect(page.getByText(/commented on your prompt/i)).toBeVisible();
});
```

## Logging Requirements
- Log comment operations
- Log moderation actions
- Screenshot comment threads
- Log notification delivery

## Files to Create
- e2e/comments/posting.spec.ts
- e2e/comments/threading.spec.ts
- e2e/comments/moderation.spec.ts
- e2e/comments/notifications.spec.ts

## Success Criteria
- Comments work correctly
- Threading displays properly
- Moderation tools function
- Notifications sent
